import { CommonModule } from '@angular/common';
import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { GiftModel, AddGift } from '../../Models/Gift';
import { GiftsService } from '../../Services/GiftsService';
import { Router, NavigationEnd } from '@angular/router';
import { Observable, filter, map, startWith, switchMap } from 'rxjs';
import { DataViewModule } from 'primeng/dataview';
import { TagModule } from 'primeng/tag';
// import { SelectModule } from 'primeng/select';
import { SelectButtonModule } from 'primeng/selectbutton';

import { ButtonModule } from 'primeng/button';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { DialogModule } from 'primeng/dialog';
import { Category } from '../../Models/Category';
import { CategoryService } from '../../Services/CategoryService';
import { AuthorService } from '../../Services/AutorService';
import { PaginatorModule } from 'primeng/paginator';
import { DropdownModule } from 'primeng/dropdown'; // בגרסה 17 קוראים לזה Dropdown ולא Select
import { InputTextModule } from 'primeng/inputtext';
import { jwtDecode } from 'jwt-decode';
import { CartService } from '../../Services/CartService';
import { provideAnimations } from '@angular/platform-browser/animations'; // חשוב לאנימציות של ה-Dropdown
@Component({
  selector: 'app-all-gifts-comp',
  standalone: true,
  imports: [CommonModule, FormsModule, DataViewModule, SelectButtonModule, TagModule, ButtonModule, ProgressSpinnerModule, DialogModule, PaginatorModule, DropdownModule, InputTextModule, provideAnimations()],
  templateUrl: './all-gifts-comp.html',
  styleUrl: './all-gifts-comp.scss',
})
export class AllGiftsComp implements OnInit {
  gifts$!: Observable<GiftModel[]>;
  isAdmin: boolean = false; // משתנה שיקבע אם להציג את הכפתורים
  categories$!: Observable<Category[]>;
  displayEditDialog: boolean = false;
  selectedGiftForEdit: any = {}; // יחזיק את המתנה שאנחנו עורכים כרגע
  errorMessage: string = '';
  allGifts: GiftModel[] = [];        // כאן נשמור את כל המתנות מהשרת
  pagedGifts: GiftModel[] = [];      // כאן נשמור רק את המתנות שיוצגו בעמוד הנוכחי
  // הגדרות פגינציה
  first: number = 0;
  rows: number = 6; // כמה מוצרים להציג בעמוד
  cartUserId: number | null = null;





  displayAddDialog: boolean = false;//למנהל להוסיף מתנה
  constructor(private giftService: GiftsService, private authorService: AuthorService, private categoryService: CategoryService, private router: Router, private cdr: ChangeDetectorRef, private cartService: CartService) {
  }

  newGift: AddGift = {
    Name: '',
    Description: '',
    CategoryId: 1,
    TicketPrice: 10,
    Image: '',
    DonorId: 1
  };

  ngOnInit() {
    this.checkAdminStatus();
    const token = localStorage.getItem('authToken');
    if (token) {
      try {
        const decodedToken: any = jwtDecode(token);
        const key = 'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier';
        this.cartUserId = decodedToken[key];
      } catch (error) {
        console.error('Invalid token:', error);
      }
    }

    this.loadGifts();
    this.categories$ = this.categoryService.getCategories();
    this.router.events.pipe(
      filter(event => event instanceof NavigationEnd)
    ).subscribe(() => {
      this.loadGifts();
      this.checkAdminStatus();
    });
  }
  checkAdminStatus() {
    // קריאה פשוטה ונקייה ל-Service
    this.isAdmin = this.authorService.isManager();
  }
  openAddGiftDialog() {
    // איפוס האובייקט לפני פתיחה
    this.errorMessage = '';
    this.newGift = { Name: '', Description: '', CategoryId: 1, TicketPrice: 10, Image: '', DonorId: 1 };
    this.displayAddDialog = true;
  }

  saveNewGift() {
    // console.log('הערך שנבחר בקטגוריה:', this.newGift.CategoryId);
    // if (this.newGift.CategoryId <= 0 || this.newGift.DonorId <= 0) {
    //     alert('נא לבחור קטגוריה ותורם (חייב להיות גדול מ-0)');
    //     return;
    // }
    // this.newGift.CategoryId = 1;
    this.errorMessage = '';
    if (!this.newGift.Name || !this.newGift.Description || !this.newGift.TicketPrice || !this.newGift.DonorId || !this.newGift.Image) {
      this.errorMessage = "נא למלא את כל שדות החובה לפני השמירה";
      return; // עוצר את הפונקציה כאן ולא שולח לשרת
    }
    this.giftService.addGift(this.newGift).subscribe({
      next: (res) => {
        console.log('המתנה נוספה בהצלחה!');
        this.displayAddDialog = false;
        this.loadGifts();
      },
      error: (err) => {

        if (err.error && err.error.errors) {
          const errors = err.error.errors;
          // הופך את אובייקט השגיאות לטקסט קריא אחד המופרד בפסיקים
          this.errorMessage = Object.values(errors).flat().join(', ');
        } else {
          this.errorMessage = 'אירעה שגיאה בשמירת המתנה.';
        }

        // פותר את בעיית ה-ExpressionChanged שהראית בתמונה
        this.cdr.detectChanges();
      }
    });
  }

  onSortChange(event: any) {
    const value = event.value;
  }
  loadGifts() {
    this.gifts$ = this.giftService.getGifts();
    this.gifts$.subscribe({
      next: (data) => {
        this.allGifts = data; // כאן הנתונים נשמרים במערך
        this.updatePage();    // כאן אנחנו חותכים את ה-6 הראשונים
        this.cdr.detectChanges(); // עדכון התצוגה
      },
      error: (err) => console.error("Error loading gifts", err)
    });
  }


  onPageChange(event: any) {
    this.first = event.first;
    this.rows = event.rows;
    this.updatePage();
  }

  // פונקציית עזר שחותכת את המערך בהתאם לעמוד
  updatePage() {
    this.pagedGifts = this.allGifts.slice(this.first, this.first + this.rows);
  }

  GetById(id: number) {
    this.router.navigate(['/gift', id]);
  }
  deleteGift(id: number) {
    if (confirm('האם את בטוחה שברצונך למחוק את המתנה הזו?')) {
      this.giftService.deleteGift(id).subscribe({
        next: (res) => {
          console.log('המתנה נמחקה בהצלחה');
          // מכיוון שה-API שלך מחזיר את הרשימה המעודכנת אחרי מחיקה:
          this.loadGifts();
        },
        error: (err) => {
          console.error('שגיאה במחיקה:', err);
          alert('לא ניתן למחוק את המתנה (ייתכן שהיא כבר נרכשה)');
        }
      });
    }
  }
  openEditGiftDialog(gift: GiftModel) {
    // אנחנו יוצרים עותק של המתנה כדי שהשינויים בתיבות הטקסט לא ישפיעו על הרשימה לפני שלחצנו "שמור"
    this.selectedGiftForEdit = { ...gift };
    this.displayEditDialog = true;
  }
  updateGift() {
    const g = this.selectedGiftForEdit;
    if (!g.name || !g.description || !g.ticketPrice || !g.donorId || !g.categoryId || !g.image) {
      this.errorMessage = "נא למלא את כל שדות החובה לפני העדכון";
      return; // עוצר כאן ולא ממשיך לקריאת ה-API
    }
    this.errorMessage = '';
    this.giftService.updateGift(this.selectedGiftForEdit.id, this.selectedGiftForEdit).subscribe({
      next: (res) => {
        console.log('המתנה עודכנה בהצלחה!');
        this.displayEditDialog = false;
        this.loadGifts(); // רענון הרשימה
      },
      error: (err) => {
        if (err.error && err.error.errors) {
          const errors = err.error.errors;
          this.errorMessage = Object.values(errors).flat().join(', ');
        } else {
          this.errorMessage = 'אירעה שגיאה בשמירת המתנה.';
        }

        // 2. הפתרון לשגיאה שראית בקונסול:
        // מאלץ את אנגולר לזהות את השינוי ב-errorMessage מיד
        this.cdr.detectChanges();
      }
    });
  }

  addToCart(giftId: number) {
    if (!this.cartUserId) {
      console.log('You must be logged in to add items to cart');
      return;
    }

    this.cartService.AddGiftToCart({ userId: this.cartUserId, giftId }).subscribe({
      next: (data) => {
        console.log(`Gift ${giftId} added to cart`, data);
        // אפשר להוסיף הודעה יפה ל-Popup / Toast
      },
      error: (err) => {
        console.error('Error adding gift to cart', err);
        alert('לא ניתן להוסיף את המתנה לסל (ייתכן שכבר נרכשה)');
      }
    });
  }

}
